" ) ; state . out . println ( "Switch to the specified keyspace. The optional username and password fields" ) ; state . out . println ( "are needed when performing authentication.
" ) ; break ; case CliParser . NODE_DESCRIBE_TABLE : state . out . println ( "describe keyspace (<keyspace>)?;
