examples:" ) ; state . out . println ( "update keyspace foo with" ) ; state . out . println ( "        placement_strategy = 'org.apache.cassandra.locator.SimpleStrategy';" ) ; state . out . println ( "        and replication_factor = 3;" ) ; state . out . println ( "update keyspace foo with" ) ; state . out . println ( "        placement_strategy = 'org.apache.cassandra.locator.NetworkTopologyStrategy';" ) ; state . out . println ( "        and strategy_options=[{DC1:2, DC2:2}];" ) ; break ; case CliParser . NODE_ADD_COLUMN_FAMILY : state . out . println ( "create column family Bar;" ) ; state . out . println ( "create column family Bar with <att1>=<value1>;" ) ; state . out . println ( "create column family Bar with <att1>=<value1> and <att2>=<value2>...;
