" ) ; state . out . println ( "get <cf>['<key>']['<super>']['<col>'] (as <type>)*;" ) ; state . out . print ( "Note: `as <type>` is optional, it dynamically converts column value to the specified type" ) ; state . out . println ( ", column value validator will be set to <type>." ) ; state . out . println ( "Available functions: " + CliClient . Function . getFunctionNames ( ) ) ; state . out . println ( "Available types: IntegerType, LongType, UTF8Type, ASCIIType, TimeUUIDType, LexicalUUIDType.
