" ) ; state . out . println ( "Assume one of the attributes (comparator, sub_comparator, validator or keys)" ) ; state . out . println ( "of the given column family to match specified type. Available types: " + CliClient . Function . getFunctionNames ( ) ) ; state . out . println ( "example:" ) ; state . out . println ( "assume Users comparator as lexicaluuid;" ) ; break ; default : state . out . println ( "?" ) ; break ; } } else { state . out . println ( "List of all CLI commands:" ) ; state . out . println ( "?                                                          Display this message." ) ; state . out . println ( "help;                                                         Display this help." ) ; state . out . println ( "help <command>;                         Display detailed, command-specific help." ) ; state . out . println ( "connect <hostname>/<port> (<username> '<password>')?; Connect to thrift service." ) ; state . out . println ( "use <keyspace> [<username> 'password'];                    Switch to a keyspace." ) ; state . out . println ( "describe keyspace (<keyspacename>)?;                          Describe keyspace." ) ; state . out . println ( "exit;                                                                  Exit CLI." ) ; state . out . println ( "quit;                                                                  Exit CLI." ) ; state . out . println ( "describe cluster;                             Display information about cluster." ) ; state . out . println ( "show cluster name;                                         Display cluster name." ) ; state . out . println ( "show keyspaces;                                          Show list of keyspaces." ) ; state . out . println ( "show api version;                                       Show server API version." ) ; state . out . println ( "create keyspace <keyspace> [with <att1>=<value1> [and <att2>=<value2> ...]];" ) ; state . out . println ( "                Add a new keyspace with the