te column." ) ; state . out . println ( "del <cf>['<key>']['<super>']['<col>'];                        Delete sub column." ) ; state . out . println ( "count <cf>['<key>'];                                    Count columns in record." ) ; state . out . println ( "count <cf>['<key>']['<super>'];                 Count columns in a super column." ) ; state . out . println ( "truncate <column_family>;                      Truncate specified column family." ) ; state . out . println ( "assume <column_family> <attribute> as <type>;" ) ; state . out . println ( "              Assume a given column family attributes to match a specified type." ) ; state . out . println ( "list <cf>;                                   List all rows in the column family." ) ; state . out . println ( "list <cf>[<startKey>:];" ) ; state . out . println ( "                       List rows in the column family beginning with <startKey>." ) ; state . out . println ( "list <cf>[<startKey>:<endKey>];" ) ; state . out . println ( "        List rows in the column family in the range from <startKey> to <endKey>." ) ; state . out . println ( "list ... limit N;                                   Limit the list results to N." ) ; } }
